payload.raw:
{
  "layout": "comparison",
  "title": "创新领域现状",
  "subtitle": "柔性传感与手势识别技术路径对比",
  "left": {
    "heading": "本项目核心技术路径",
    "items": ["均致力于提升人机交互体验", "!全栈自研，实现硬件级漂移抑制与高精度识别", "集成压力梯度与温控反馈，构建多模态闭环交互系统", "开发标准化协议，与10余种国产设备无缝对接", "目标精度0.1mm、延迟<20ms、识别率>97%"],
    "tone": "positive"
  },
  "right": {
    "heading": "现有技术现状与不足",
    "items": ["均致力于提升人机交互体验", "!传感器迟滞误差高（>15%）、环境稳定性弱、成本高昂", "手势识别算法在复杂工况下精度不足92%、延迟超80ms", "多模态交互缺乏“感知-意图-反馈”闭环设计", "与国产XR平台深度适配方案稀缺，触觉反馈技术不成熟"],
    "tone": "negative"
  }
}

