payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1-2月",
      "title": "硬件攻坚",
      "description": "完成传感器微结构设计、液态金属-聚氨酯复合材料制备与信号标定，构建融合光纤与IMU的混合传感架构，实现0.1mm级空间分辨率。核心团队包括2名硬件工程师与1名材料研究员，需柔性材料合成设备与高精度信号采集平台支持，预算22万元。"
    },
    {
      "date": "第3月",
      "title": "算法开发",
      "description": "开发轻量化手势识别分层模型，结合时序滑动窗口分割与噪声抑制模块，实现毫秒级实时推理。同时开发基于统一时空对齐协议的多模态融合引擎，支持视觉-触觉-听觉数据低延迟融合。团队由3名算法工程师与1名数据标注员组成，需GPU服务器与仿真环境，预算18万元。"
    },
    {
      "date": "第4月",
      "title": "系统集成",
      "description": "进行软硬件联调，集成多模态交互协议栈，并嵌入微型电磁致动器阵列与半导体温控模块构成的触觉反馈执行单元，构建感知-意图-反馈闭环。团队包括2名全栈工程师与2名测试工程师，需多模态测试舱与合作设备接口，预算15万元。"
    },
    {
      "date": "第5-6月",
      "title": "场景验证与优化",
      "description": "依托H-Box全息舱、李未可眼镜等合作平台，开展工业级远程操控、虚拟实训等多场景压力测试，收集用户体验并进行迭代优化，最终形成可复用的交互标准接口。团队由1名产品经理与2名场景测试员主导，需远程操控实训场地与用户反馈系统，预算15万元。"
    }
  ]
}

